queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?facilityname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFacilities ?child ; p:hasCruise_Ships ?parent . } GROUP BY ?child }
  ?child p:facilityName ?facilityname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Cruise_Ships } }
  FILTER(?nf = ?total)
}

